{
  "domain_analysis": {
    "business_context": "A global logistics platform adding real-time driver earnings transparency across three jurisdictions with fundamentally different labor classifications, regulatory requirements, and co-determination obligations. This is not a single feature — it is three distinct compliance regimes unified under one product surface.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for a delivery task, calculated before bonuses, tips, or deductions. For employees (CA), this must meet or exceed minimum wage guarantees. For contractors (Indonesia), this is the agreed task rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completing individual deliveries, potentially influenced by surge pricing, distance, or time-of-day multipliers." },
      { "term": "Tip", "definition": "Voluntary gratuity from the customer to the driver. Must never be commingled with base pay or used to satisfy minimum wage obligations (CA law)." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings — e.g., equipment fees, insurance contributions, platform fees, tax withholdings. Each deduction must be individually itemized and attributable to a specific category." },
      { "term": "Earnings Breakdown", "definition": "The structured, itemized view of all compensation components for a given period, showing how gross pay becomes net pay." },
      { "term": "Driver Classification", "definition": "The legal employment status of the driver — employee (CA under AB5, Germany) or independent contractor (Indonesia) — which determines applicable labor law, tax treatment, and transparency obligations." },
      { "term": "Works Council (Betriebsrat)", "definition": "The legally mandated employee representative body in Germany that holds co-determination rights over changes to compensation display and monitoring systems under the BetrVG (Works Constitution Act)." },
      { "term": "Real-Time", "definition": "Earnings data updated and visible to the driver within the current active session or shift, not delayed to end-of-pay-period. Does not necessarily mean sub-second — means 'before the driver's work session ends.'" },
      { "term": "Minimum Wage Guarantee", "definition": "The legal floor for hourly compensation applicable to employee-classified drivers. In CA, the platform must ensure total hourly earnings (excluding tips) meet or exceed the state minimum wage." },
      { "term": "Pay Period", "definition": "The defined interval over which earnings are aggregated for payment. Jurisdiction-specific: may be weekly, bi-weekly, or monthly." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Tips must never be included in the base pay calculation or used to satisfy minimum wage obligations in employee-classified jurisdictions (California).",
      "invariant": true,
      "invariant_justification": "Commingling tips with base pay to meet minimum wage is a violation of California Labor Code §351 and constitutes wage theft. This is a legal constraint, not a policy choice.",
      "testable_assertion": "ASSERT: In California, the sum of (base_pay + per_delivery_bonus) / hours_worked >= state_minimum_wage, calculated WITHOUT including tips."
    },
    {
      "id": "BR-2",
      "rule": "Every deduction displayed must be individually itemized with a category label, amount, and legal or contractual basis. No 'miscellaneous' or 'other' aggregate deductions are permitted.",
      "invariant": true,
      "invariant_justification": "Unitemized deductions violate California wage statement requirements (Labor Code §226) and undermine the core purpose of earnings transparency. An opaque deduction line defeats the feature's business intent.",
      "testable_assertion": "ASSERT: Every deduction entry has a non-empty category, a non-zero amount, and a reference to either a legal requirement or a contractual clause."
    },
    {
      "id": "BR-3",
      "rule": "The earnings breakdown must display exactly four top-level components: base pay, per-delivery bonus, tips, and deductions. No component may be hidden or collapsed by default.",
      "invariant": false,
      "invariant_justification": "The four-component structure is a product decision that could evolve (e.g., adding 'surge bonus' as a fifth component). A VP could change the display taxonomy.",
      "testable_assertion": "ASSERT: The earnings breakdown response contains exactly the fields: base_pay, per_delivery_bonus, tips, deductions, and all are visible in the default UI state."
    },
    {
      "id": "BR-4",
      "rule": "The Germany rollout of the compensation display system must not go live until explicit written approval from the applicable Betriebsrat (works council) is recorded in the system.",
      "invariant": true,
      "invariant_justification": "Under §87(1) No. 6 of the BetrVG, the works council has co-determination rights over technical systems that monitor employee performance or behavior. Compensation display systems qualify. Deploying without approval is a legal violation that can result in injunctions.",
      "testable_assertion": "ASSERT: The feature flag for Germany earnings transparency cannot be enabled unless a works_council_approval record exists with status=APPROVED and a date on or before the activation date."
    },
    {
      "id": "BR-5",
      "rule": "Driver classification (employee vs. independent contractor) must be resolved per jurisdiction and must govern which earnings rules, deduction categories, and legal disclosures apply. Classification is never inferred — it is an explicit, jurisdiction-level configuration.",
      "invariant": true,
      "invariant_justification": "Misclassification has catastrophic legal consequences (AB5 penalties in CA, tax fraud implications globally). The system must never guess or default classification — it must be explicitly set per jurisdiction.",
      "testable_assertion": "ASSERT: Every driver has an explicit classification enum (EMPLOYEE | INDEPENDENT_CONTRACTOR) linked to their jurisdiction. No null or default values are permitted."
    },
    {
      "id": "BR-6",
      "rule": "In California, the platform must display a compliant wage statement that includes: gross wages earned, total hours worked, all deductions, net wages, pay period dates, and employer legal name. This must conform to Labor Code §226(a).",
      "invariant": true,
      "invariant_justification": "California Labor Code §226(a) mandates specific itemized wage statement contents. Non-compliance results in statutory penalties per pay period per employee.",
      "testable_assertion": "ASSERT: For California drivers, the earnings view includes: gross_wages, hours_worked, itemized_deductions, net_wages, pay_period_start, pay_period_end, and employer_legal_name."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data must be available to the driver in real time — defined as updated before the driver's current active session or shift ends. Stale or end-of-period-only data does not satisfy the feature requirement.",
      "invariant": false,
      "invariant_justification": "The definition of 'real time' is a product decision. The business could decide daily batches are acceptable in some markets. The latency SLA is a policy, not a physical constraint.",
      "testable_assertion": "ASSERT: After a delivery is marked complete, the driver's earnings breakdown reflects the updated totals within 5 minutes."
    },
    {
      "id": "BR-8",
      "rule": "In Indonesia, where drivers are independent contractors, the earnings display must frame compensation as 'task payments' or 'service fees' — never as 'wages,' 'salary,' or 'pay' — to avoid implying an employment relationship.",
      "invariant": true,
      "invariant_justification": "Using employment-related terminology for independent contractors creates legal risk of reclassification. Language in the UI is a legal artifact, not just a UX choice.",
      "testable_assertion": "ASSERT: In the Indonesian locale, no UI string in the earnings breakdown contains the words 'wage', 'salary', 'pay', or their Indonesian equivalents ('gaji', 'upah') when referring to the driver's compensation."
    },
    {
      "id": "BR-9",
      "rule": "Deductions for employee-classified drivers require explicit prior consent or a legal mandate. The platform cannot unilaterally introduce new deduction categories without driver acknowledgment (CA) or works council approval (Germany).",
      "invariant": true,
      "invariant_justification": "Unauthorized deductions from employee wages violate labor codes in both California and Germany. This is a legal constraint on system behavior.",
      "testable_assertion": "ASSERT: No new deduction category can be applied to an employee-classified driver's earnings unless a consent_record or legal_mandate_reference exists for that category."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and itemized deductions as separate line items, with tips explicitly excluded from the base pay / minimum wage calculation"
    },
    {
      "id": "AC-2",
      "given": "A driver in California views their earnings",
      "when": "The earnings breakdown is rendered",
      "then": "It includes all fields required by Labor Code §226(a): gross wages, total hours worked, itemized deductions, net wages, pay period dates, and employer legal name"
    },
    {
      "id": "AC-3",
      "given": "The Germany market has no works council approval on record",
      "when": "An operator attempts to enable the earnings transparency feature for Germany",
      "then": "The system rejects the activation and returns an error referencing the missing Betriebsrat approval"
    },
    {
      "id": "AC-4",
      "given": "A driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "All compensation labels use contractor-appropriate terminology (e.g., 'task payment', 'service fee') and no employment-implying terms appear"
    },
    {
      "id": "AC-5",
      "given": "A delivery is marked complete for any driver in any jurisdiction",
      "when": "The driver checks their earnings within 5 minutes",
      "then": "The earnings breakdown reflects the completed delivery's contribution to all applicable components"
    },
    {
      "id": "AC-6",
      "given": "A driver exists in the system",
      "when": "Their profile is loaded",
      "then": "They have an explicit, non-null classification (EMPLOYEE or INDEPENDENT_CONTRACTOR) linked to their jurisdiction"
    },
    {
      "id": "AC-7",
      "given": "An admin attempts to add a new deduction category for employee-classified drivers",
      "when": "No driver consent record or legal mandate reference exists for that category",
      "then": "The system rejects the deduction category and does not apply it to any earnings calculations"
    },
    {
      "id": "AC-8",
      "given": "A driver in California has earnings where (base_pay + per_delivery_bonus) / hours_worked falls below the state minimum wage",
      "when": "The earnings breakdown is calculated",
      "then": "A minimum wage top-up adjustment is added to base pay to reach compliance, and this adjustment is displayed as a separate visible line item"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-engagement",
      "expected_behavior": "Driver classification must be updated to EMPLOYEE before any work is performed in CA. Historical Indonesian earnings remain labeled as contractor payments. The transition date must be recorded, and no hybrid classification is permitted for any single pay period."
    },
    {
      "scenario": "A California driver works a shift where base pay + bonuses = $0 but receives $50 in tips",
      "expected_behavior": "The system must flag a minimum wage violation. Tips cannot backfill the $0 base. A minimum wage top-up must be calculated based on hours worked and added as a separate line item. The driver sees: Base Pay: $X (minimum wage top-up), Bonus: $0, Tips: $50."
    },
    {
      "scenario": "Germany works council approval is granted, then later revoked",
      "expected_behavior": "The feature must be immediately disabled for German drivers. The system must support approval revocation as a state transition, not just presence/absence of approval. Existing earnings data remains accessible but the real-time display is suspended."
    },
    {
      "scenario": "A deduction exceeds the driver's gross earnings for a period, resulting in negative net pay",
      "expected_behavior": "For employee-classified drivers (CA, Germany), negative net pay is illegal — deductions must be capped so net pay >= 0 for the period. For contractors (Indonesia), the platform should display the negative balance but flag it for review, as contractor agreements may permit it."
    },
    {
      "scenario": "Multiple deliveries complete simultaneously and the real-time update races",
      "expected_behavior": "The earnings breakdown must be eventually consistent and monotonically increasing within a session (barring legitimate deductions). A driver must never see their earnings decrease and then increase due to race conditions."
    },
    {
      "scenario": "Indonesian regulatory environment changes and drivers are reclassified as employees",
      "expected_behavior": "The jurisdiction-level classification configuration must be updated. All terminology, deduction rules, and wage protections must switch to employee mode. This is a configuration change, not a code change — the system must be designed to handle classification as data, not logic branches."
    },
    {
      "scenario": "A California driver's shift spans midnight and the minimum wage rate changes on the new calendar day",
      "expected_behavior": "Hours worked before and after midnight must be calculated against their respective minimum wage rates. The earnings breakdown must show the correct top-up amount reflecting the blended rate."
    }
  ],

  "business_impact": {
    "financial": "Non-compliance penalties are severe: California Labor Code §226 violations carry $50/employee for first offense, $100/employee for subsequent, plus actual damages. German BetrVG violations can result in injunctions halting the feature entirely. Correct implementation protects against class-action wage theft litigation, which in CA alone can reach 8-figure settlements for platform companies.",
    "operational": "This feature requires jurisdiction-aware configuration management, works council workflow integration for Germany, and locale-specific terminology pipelines. Operational complexity is high — this is effectively three separate compliance regimes behind one UI. The works council gate for Germany will likely delay that market's rollout by 3-6 months.",
    "user": "Drivers gain trust and retention improves when they understand exactly how their earnings are calculated. In California, this is not optional — it is a legal right. For Indonesian contractors, transparent task payments reduce disputes and support calls. Industry data suggests earnings transparency correlates with 10-15% improvement in driver retention.",
    "risk": "The highest risk is treating this as a single global feature rather than three jurisdiction-specific compliance implementations sharing a UI framework. A second critical risk is terminology drift — using 'wages' for contractors or 'task payments' for employees could trigger reclassification litigation or regulatory scrutiny. Legal review is essential before any market launch.",
    "stakeholders_affected": [
      { "group": "Drivers (CA)", "impact": "Gain legally mandated wage transparency. Must see compliant itemized wage statements. Failure exposes them to wage theft." },
      { "group": "Drivers (Germany)", "impact": "Cannot access feature until works council approves. Delayed access relative to other markets." },
      { "group": "Drivers (Indonesia)", "impact": "Gain voluntary transparency into task-based earnings. Terminology must not imply employment relationship." },
      { "group": "Legal / Compliance Team", "impact": "Must review and approve all UI copy, deduction categories, and wage calculation logic per jurisdiction before launch. Ongoing obligation to monitor regulatory changes." },
      { "group": "German Works Council (Betriebsrat)", "impact": "Has legal right to review, negotiate, and approve or reject the system. Must be engaged as a stakeholder, not merely notified." },
      { "group": "Product / Engineering", "impact": "Must build jurisdiction-aware earnings engine, not a one-size-fits-all display. Feature flags, classification-driven logic, and locale-aware terminology are architectural requirements." },
      { "group": "Finance / Payroll", "impact": "Earnings breakdown must reconcile exactly with payroll records. Any discrepancy between what the driver sees and what payroll processes is a compliance and trust failure." },
      { "group": "Customer Support", "impact": "Will receive increased inquiries as drivers engage with detailed earnings data. Must be trained on jurisdiction-specific rules to handle disputes accurately." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is a single sentence requesting a feature across three radically different legal regimes without acknowledging the jurisdictional complexity. Critical details are unspecified: minimum wage top-up display logic, deduction consent workflows, works council engagement timeline, data retention requirements, and the exact definition of 'real time.' Additionally, labor law compliance requires legal review that this domain analysis cannot substitute for — particularly around AB5 edge cases and BetrVG co-determination scope.",
    "high_confidence_areas": [
      "Tips must not count toward minimum wage in California — this is settled law",
      "Works council approval is legally required in Germany before deployment — this is black-letter BetrVG",
      "Driver classification must be explicit and jurisdiction-bound — misclassification risk is existential",
      "Contractor terminology must avoid employment-implying language in Indonesia"
    ],
    "low_confidence_areas": [
      "Exact scope of BetrVG co-determination for this specific feature type — works council may demand broader scope than just the display",
      "Whether Indonesian regulations impose any contractor payment transparency requirements not mentioned in the spec",
      "Tax withholding display requirements per jurisdiction — not addressed in the spec at all",
      "Data retention and audit trail requirements for displayed earnings — varies by jurisdiction",
      "Whether 'real-time' has regulatory implications in California (e.g., must be available during the shift vs. within 24 hours)"
    ],
    "assumptions": [
      "The platform has an existing driver classification system that can be extended, not built from scratch",
      "Works council engagement for Germany has not yet begun — the feature gate must be built before negotiations start",
      "The four-component earnings breakdown (base, bonus, tips, deductions) is the intended product taxonomy, though deductions may have sub-categories",
      "The platform already has locale/i18n infrastructure that can support jurisdiction-specific terminology",
      "Legal review will be conducted before any market launch — this analysis identifies domain rules but does not constitute legal advice"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define latency requirements. In California, there may be a legal distinction between 'available during the shift' and 'available within X hours.' The acceptable update latency directly impacts architecture (streaming vs. polling vs. batch).",
      "affected_stakeholders": ["Engineering", "Legal / Compliance", "Drivers (all jurisdictions)"],
      "options": [
        "Define real-time as 'within 5 minutes of delivery completion' — practical for most architectures",
        "Define real-time as 'streaming/live update during active session' — requires WebSocket or push infrastructure",
        "Define real-time as 'before end of shift/session' — loosest interpretation, simplest to build"
      ],
      "recommendation": "Start with 'within 5 minutes of delivery completion' as the SLA, and verify with California legal counsel whether this satisfies any regulatory real-time requirements."
    },
    {
      "type": "missing_context",
      "description": "The spec does not address tax withholding display. In California, employee wage statements must show tax withholdings. In Indonesia, tax treatment for contractor payments may require different disclosures. Are tax withholdings part of 'deductions' or a separate component?",
      "affected_stakeholders": ["Finance / Payroll", "Legal / Compliance", "Drivers (all jurisdictions)"],
      "options": [
        "Include tax withholdings as a sub-category of deductions",
        "Add a fifth top-level component: 'Tax Withholdings'",
        "Exclude tax withholdings from this feature and handle in a separate payroll view"
      ],
      "recommendation": "Include tax withholdings as itemized sub-entries under deductions for employees, and clarify with legal whether Indonesian contractor payments require any tax-related disclosures."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not define what happens when the works council rejects or delays approval in Germany. Is Germany simply excluded indefinitely? Is there a fallback (e.g., simplified earnings view that doesn't trigger co-determination)? The business needs a strategy for the likely 3-6 month delay.",
      "affected_stakeholders": ["German Works Council", "Drivers (Germany)", "Product"],
      "options": [
        "Launch in CA and Indonesia first, Germany waits for approval with no interim solution",
        "Offer a minimal 'total earnings only' view in Germany that may not trigger co-determination (requires legal opinion)",
        "Engage works council proactively before development begins to parallelize approval and build"
      ],
      "recommendation": "Engage the Betriebsrat immediately and in parallel with development. Build the feature-flag gate so Germany can be activated the moment approval is received. Do not attempt a 'minimal view' workaround without explicit legal guidance."
    }
  ],

  "rejection_reasons": []
}

